#!/usr/bin/env python3
"""Generate GoalOS Public Proof Mission 003 as an additive website overlay.

The canonical v86 website source is never edited. This builder operates only on
``site`` after the existing canonical builder and the Mission 001/002 overlays.
"""
from __future__ import annotations

import argparse
import csv
import hashlib
import html
import json
import re
from pathlib import Path
from typing import Any

START = "<!-- GOALOS_PROOF_MISSION_003_START -->"
END = "<!-- GOALOS_PROOF_MISSION_003_END -->"
STYLE_START = "<!-- GOALOS_PROOF_MISSION_003_STYLE_START -->"
STYLE_END = "<!-- GOALOS_PROOF_MISSION_003_STYLE_END -->"
MISSION2_END = "<!-- GOALOS_PROOF_MISSION_002_END -->"
MISSION1_END = "<!-- GOALOS_PROOF_GRADIENT_SOVEREIGN_END -->"
PAGE = "proof-mission-003.html"
HUB = "proof-missions.html"
CANONICAL = "0xA61a3B3a130a9c20768EEBF97E21515A6046a1fA"
FORBIDDEN_PUBLIC = (
    "recursive.com",
    "recursive org",
    "recursive-style",
    "competitor comparison",
    "named competitor",
)


def fail(message: str) -> None:
    raise RuntimeError(message)


def load(path: Path) -> dict[str, Any]:
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception as exc:
        fail(f"cannot read {path}: {exc}")


def dump(path: Path, value: Any) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(value, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")


def sha256(path: Path) -> str:
    return hashlib.sha256(path.read_bytes()).hexdigest()


def esc(value: Any) -> str:
    return html.escape(str(value), quote=True)


def validate(content: dict[str, Any], mainnet: dict[str, Any]) -> None:
    if content.get("missionId") != "GOALOS-PUBLIC-PROOF-MISSION-003":
        fail("wrong Mission 003 identifier")
    if content.get("sequence") != 3:
        fail("Mission 003 sequence must be 3")
    if content.get("status") != "PROTOCOL_PUBLISHED_AWAITING_THREE_TRANSFER_PROVEN_CAPABILITIES":
        fail("unexpected Mission 003 status")
    if sum(int(item.get("share", 0)) for item in content.get("settlement", [])) != 100:
        fail("Mission 003 settlement shares must total 100")
    if len(content.get("proofRoute", [])) != 24:
        fail("Mission 003 proof route must contain 24 stages")
    if mainnet.get("chainId") != 1:
        fail("Mainnet data must use chainId 1")
    if mainnet.get("canonicalAgialpha", "").lower() != CANONICAL.lower():
        fail("wrong canonical AGIALPHA")
    if mainnet.get("goalosCreatedContractCount") != 48:
        fail("expected 48 GoalOS-created contracts")
    verification = mainnet.get("verification", {})
    if verification.get("verified") != 48 or verification.get("failed") != 0:
        fail("expected 48 verified and 0 failed")
    if mainnet.get("deploymentStatus") != "CONFIGURED":
        fail("Mainnet deployment is not CONFIGURED")
    if mainnet.get("phaseBGrantCount") != 14:
        fail("expected 14 configured grants")
    postcheck = mainnet.get("postcheck", {})
    if postcheck.get("status") != "PASSED" or postcheck.get("checkedContracts") != 48:
        fail("postcheck does not cover 48 contracts")
    names = {entry["name"] for entry in mainnet.get("contracts", [])}
    missing = [entry["contractName"] for entry in content.get("proofRoute", []) if entry["contractName"] not in names]
    if missing:
        fail("unknown proof-route contracts: " + ", ".join(missing))
    public_blob = json.dumps(content, ensure_ascii=False).lower()
    for forbidden in FORBIDDEN_PUBLIC:
        if forbidden in public_blob:
            fail(f"prohibited public reference: {forbidden}")


def constellation_svg() -> str:
    nodes = [
        (250, 75, "M2-A"), (410, 130, "M2-B"), (455, 290, "M2-C"),
        (360, 420, "M2-D"), (170, 430, "M2-E"), (55, 285, "M2-F"),
        (95, 130, "M2-G"),
    ]
    lines = "".join(f'<line x1="250" y1="250" x2="{x}" y2="{y}" />' for x,y,_ in nodes)
    circles = "".join(
        f'<g class="cc-star cc-s{i}"><circle cx="{x}" cy="{y}" r="28"/><text x="{x}" y="{y+4}" text-anchor="middle">{label}</text></g>'
        for i,(x,y,label) in enumerate(nodes,1)
    )
    return f'''<svg class="cc-constellation" viewBox="0 0 500 500" role="img" aria-label="Transfer-Proven capabilities composing into one governed constellation"><defs><radialGradient id="ccCore" cx="36%" cy="30%"><stop offset="0" stop-color="#fff"/><stop offset=".34" stop-color="#f5d68a"/><stop offset=".7" stop-color="#9f8bff"/><stop offset="1" stop-color="#071521"/></radialGradient><filter id="ccGlow"><feGaussianBlur stdDeviation="5" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><g class="cc-links">{lines}</g>{circles}<circle class="cc-orbit" cx="250" cy="250" r="170"/><circle class="cc-orbit o2" cx="250" cy="250" r="115"/><g class="cc-center" filter="url(#ccGlow)"><circle cx="250" cy="250" r="70" fill="url(#ccCore)"/><text x="250" y="242" text-anchor="middle">M3</text><text class="small" x="250" y="270" text-anchor="middle">COMPOSITION</text></g></svg>'''


