def proof_route(content: dict[str, Any], mainnet: dict[str, Any]) -> str:
    contracts = {entry["name"]: entry for entry in mainnet["contracts"]}
    parts=[]
    for item in content["proofRoute"]:
        c=contracts[item["contractName"]]
        parts.append(f'''<article class="cc-route-item"><b>{int(item['sequence']):02d}</b><div><h3>{esc(item['stage'])} · {esc(item['contractName'])}</h3><p>{esc(item['purpose'])}</p></div><a href="{esc(c['etherscanUrl'])}" target="_blank" rel="noreferrer">Etherscan ↗</a></article>''')
    return "".join(parts)


def page(content: dict[str, Any], mainnet: dict[str, Any]) -> str:
    constitution="".join(f'<article class="cc-law">{esc(x)}</article>' for x in content["constitution"])
    architectures="".join(f'''<article class="cc-architecture {'treatment' if a['id']=='TREATMENT_CONSTELLATION' else ''}"><small>{esc(a['id'])}</small><h3>{esc(a['title'])}</h3><p>{esc(a['copy'])}</p></article>''' for a in content["controlArchitectures"])
    contract="".join(f'''<article class="cc-contract-card"><b>{i:02d}</b><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for i,x in enumerate(content["constellationContract"],1))
    chain="".join(f'''<article class="cc-step"><b>{i:02d}</b><div><small>{esc(x['stage'])}</small><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></div></article>''' for i,x in enumerate(content["proofChain"],1))
    gauntlet="".join(f'''<article class="cc-failure"><code>{esc(x['code'])}</code><p>{esc(x['copy'])}</p></article>''' for x in content["faultInjectionGauntlet"])
    failures="".join(f'''<article class="cc-failure"><code>{esc(x['code'])}</code><p>{esc(x['copy'])}</p></article>''' for x in content["failureAtlas"])
    criteria="".join(f'''<article class="cc-criterion"><b>{i}</b><p>{esc(x)}</p></article>''' for i,x in enumerate(content["acceptance"],1))
    validators="".join(f'''<article class="cc-validator"><strong>{esc(x['id'])}</strong><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for x in content["validators"])
    ladder="".join(f'''<article class="cc-level {'target' if x['level']=='M3' else ''}"><strong>{esc(x['level'])}</strong><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for x in content["maturityLadder"])
    settlement="".join(f'''<div class="cc-settlement-row"><span>{esc(x['label'])}</span><strong>{int(x['share'])}%</strong></div>''' for x in content["settlement"])
    boundary="".join(f'<p>{esc(x)}</p>' for x in content["claimBoundary"])
    mission_phases="".join(f'<li>{esc(x)}</li>' for x in content["compoundMission"]["requiredPhases"])
    status=esc(content["status"]).replace("_"," ").title()
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{esc(content['title'])} · GoalOS Public Proof Mission 003</title><meta name="description" content="GoalOS Public Proof Mission 003 tests whether multiple Transfer-Proven capabilities can compose into one governed, replayable, attributable, and rollback-ready intelligence system."><meta name="theme-color" content="#040812"><meta property="og:title" content="The Capability Constellation · GoalOS"><meta property="og:description" content="Where proven capabilities become a governed intelligence."><meta property="og:type" content="website"><meta property="og:url" content="https://montrealai.github.io/goalos-agialpha-ascension/{PAGE}"><meta name="twitter:card" content="summary_large_image"><link rel="canonical" href="https://montrealai.github.io/goalos-agialpha-ascension/{PAGE}"><link rel="stylesheet" href="assets/goalos-v86-preserve.css">{critical_css()}<script type="application/ld+json">{json.dumps({'@context':'https://schema.org','@type':'ResearchProject','name':content['title'],'alternateName':'GoalOS Public Proof Mission 003','description':content['objective'],'url':f'https://montrealai.github.io/goalos-agialpha-ascension/{PAGE}','isPartOf':{'@type':'WebSite','name':'GoalOS AGIALPHA Ascension'}},ensure_ascii=False)}</script></head><body class="cc-body"><a class="cc-skip" href="#main">Skip to main content</a><header class="cc-nav"><div class="cc-shell cc-navin"><a class="cc-brand" href="index.html">GoalOS <span>AGIALPHA</span></a><nav class="cc-navlinks" aria-label="Primary"><a href="proof-missions.html">Proof Missions</a><a href="proof-gradient-challenge.html">Mission 001</a><a href="proof-mission-002.html">Mission 002</a><a href="proof-mission-003.html" aria-current="page">Mission 003</a><a href="{esc(content['repositoryUrl'])}" target="_blank" rel="noreferrer">GitHub ↗</a></nav></div></header><main id="main"><section class="cc-hero"><div class="cc-shell cc-hero-grid"><div><div class="cc-kicker">{esc(content['kicker'])}</div><h1>THE CAPABILITY <span>CONSTELLATION</span></h1><p class="cc-tagline">{esc(content['subtitle'])}</p><p class="cc-question">{esc(content['heroQuestion'])}</p><div class="cc-manifesto">{esc(content['manifesto'])}</div><div class="cc-status">{status}</div><div class="cc-actions"><a class="cc-btn primary" href="#protocol">Enter the protocol</a><a class="cc-btn" href="downloads/proof-missions/public-proof-mission-003.json" download>Download Mission 003</a><a class="cc-btn" href="#mainnet">Inspect the Mainnet route</a></div></div><div class="cc-visual">{constellation_svg()}</div></div></section><section class="cc-section deep"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">The constitutional boundary</div><h2>Coordination must become more accountable as intelligence becomes more collective.</h2><p>{esc(content['publicThesis'])}</p></div><div class="cc-constitution">{constitution}</div></div></section><section class="cc-section light" id="protocol"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">The scientific question</div><h2>Can a governed organization outperform its strongest isolated member—and survive the failure of one of its own?</h2><p>{esc(content['objective'])}</p></div><div class="cc-architectures">{architectures}</div><div class="cc-metrics"><article class="cc-metric"><strong>3–5</strong><span>Transfer-Proven capabilities</span></article><article class="cc-metric"><strong>≥2</strong><span>distinct capability domains</span></article><article class="cc-metric"><strong>4</strong><span>independent validators</span></article><article class="cc-metric"><strong>7 days</strong><span>public challenge window</span></article></div></div></section><section class="cc-section violet"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">The compound mission</div><h2>{esc(content['compoundMission']['title'])}</h2><p>{esc(content['compoundMission']['brief'])}</p></div><ol>{mission_phases}</ol></div></section><section class="cc-section light"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">The constellation contract</div><h2>Six proofs before collective intelligence earns the right to act as one.</h2><p>Every capability remains bounded, attributable, interruptible, and independently challengeable inside the larger system.</p></div><div class="cc-contract">{contract}</div></div></section><section class="cc-section deep"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">The complete chain</div><h2>From transfer-proven capability to composition-proven institution.</h2><p>No stage inherits credibility from the previous one. Every transition produces evidence, failure records, and rollback conditions.</p></div><div class="cc-chain">{chain}</div></div></section><section class="cc-section light"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">The fault-injection gauntlet</div><h2>Mission 003 attacks the organization—not merely its members.</h2><p>The constellation must remain safe when interfaces drift, memory is poisoned, a member disappears, or authority attempts to expand.</p></div><div class="cc-gauntlet">{gauntlet}</div></div></section><section class="cc-section deep"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">Acceptance standard</div><h2>Composition-Proven is earned only by the entire system.</h2><p>One impressive capability cannot compensate for unsafe coordination, broken attribution, failed recovery, or unreproducible orchestration.</p></div><div class="cc-acceptance">{criteria}</div></div></section><section class="cc-section light"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">Independent decision</div><h2>Four validators. Four different reasons to refuse acceptance.</h2><p>Technical performance, compositional safety, provenance, and economic attribution are judged separately.</p></div><div class="cc-validator-grid">{validators}</div></div></section><section class="cc-section light"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">Failure atlas</div><h2>What fails remains public—and becomes institutional memory.</h2><p>A failed constellation may still produce valuable interface boundaries, fault-domain lessons, attribution rules, and rollback improvements.</p></div><div class="cc-failure-grid">{failures}</div></div></section><section class="cc-section deep"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">Capability maturity</div><h2>The ladder does not skip from success to institution.</h2><p>Mission 003 targets M3 only: a bounded Composition-Proven constellation.</p></div><div class="cc-ladder">{ladder}</div></div></section><section class="cc-section gold"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">Conditional settlement</div><h2>Collective value without erased lineage.</h2><p>Every accepted contribution remains attributable. Every replay and falsification is compensated according to the published mission contract. No challenge closure, no success settlement.</p></div><div class="cc-settlement"><div class="cc-ring-chart" aria-label="Mission 003 settlement allocation"></div><div class="cc-settlement-list">{settlement}</div></div></div></section><section class="cc-section light" id="mainnet"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">Ethereum Mainnet proof route</div><h2>Twenty-four deployed contracts map the full institutional chain.</h2><p>The configured GoalOS deployment records 48 GoalOS-created contracts, 48/48 verification, 14/14 configuration grants, and a 48-contract passing postcheck. Infrastructure is real; Mission 003 results remain evidence-gated.</p></div><div class="cc-route">{proof_route(content,mainnet)}</div></div></section><section class="cc-section light"><div class="cc-shell"><div class="cc-horizon"><div class="cc-eyebrow">The next horizon</div><h3>{esc(content['mission4']['title'])}</h3><p>{esc(content['mission4']['copy'])}</p><p><strong>Status:</strong> horizon only; not yet authorized.</p></div></div></section><section class="cc-section deep"><div class="cc-shell"><div class="cc-heading"><div class="cc-eyebrow">Claim boundary</div><h2>Prestige follows evidence. The protocol never outruns the proof.</h2></div><div class="cc-boundary">{boundary}</div><div class="cc-disclosure" style="margin-top:1.25rem">Not externally audited. No scientific, compositional, settlement, production-safety, or general-intelligence result is predeclared.</div><div class="cc-downloads" style="margin-top:1.6rem"><a href="downloads/proof-missions/public-proof-mission-003.json" download>Mission 003 JSON</a><a href="downloads/proof-missions/mission-003-constellation-manifest-template.json" download>Constellation manifest</a><a href="downloads/proof-missions/mission-003-interface-covenant-template.json" download>Interface covenant</a><a href="downloads/proof-missions/mission-003-fault-domain-register-template.json" download>Fault register</a><a href="downloads/proof-missions/mission-003-proof-route.csv" download>Mainnet route CSV</a></div></div></section></main><footer class="cc-footer"><div class="cc-shell">GoalOS AGIALPHA Ascension · Public Proof Mission 003 · The Capability Constellation · No result predeclared</div></footer><script src="assets/goalos-v86-dynamic-ai.js" defer></script></body></html>'''


