def replace_marked(text: str, start: str, end: str, replacement: str) -> str:
    return re.sub(re.escape(start) + r".*?" + re.escape(end), replacement, text, flags=re.S)


def inject_homepage(path: Path) -> None:
    raw=path.read_text(encoding="utf-8")
    style=home_style(); section=home_section()
    if STYLE_START in raw:
        raw=replace_marked(raw,STYLE_START,STYLE_END,style)
    else:
        raw=raw.replace("</head>",style+"\n</head>",1)
    if START in raw:
        raw=replace_marked(raw,START,END,section)
    elif MISSION2_END in raw:
        raw=raw.replace(MISSION2_END,MISSION2_END+"\n"+section,1)
    elif MISSION1_END in raw:
        raw=raw.replace(MISSION1_END,MISSION1_END+"\n"+section,1)
    else:
        anchor="<section class='asi-section white'><div class='asi-wrap'><div class='asi-kicker'>World-launch command pages</div>"
        if anchor not in raw: fail("homepage insertion anchor not found")
        raw=raw.replace(anchor,section+"\n"+anchor,1)
    path.write_text(raw,encoding="utf-8")


def write_downloads(site: Path, content: dict[str, Any], mainnet: dict[str, Any]) -> None:
    out=site/"downloads"/"proof-missions"; out.mkdir(parents=True,exist_ok=True)
    dump(out/"public-proof-mission-003.json",content)
    dump(out/"mission-003-constellation-manifest-template.json",{
        "schemaVersion":"1.0","missionId":content["missionId"],"constellationId":"TO_BE_ASSIGNED",
        "members":[],"objectiveCommitment":"TO_BE_COMMITTED","authorityGraph":[],"sharedMemoryPolicy":{},
        "resourceCeilings":{},"faultDomains":[],"attributionPolicy":{},"rollbackTree":[],"status":"TEMPLATE_NOT_EVIDENCE"
    })
    dump(out/"mission-003-interface-covenant-template.json",{
        "schemaVersion":"1.0","capabilityId":"TO_BE_BOUND","interfaceId":"TO_BE_ASSIGNED","inputs":[],"outputs":[],
        "requiredEvidence":[],"timeouts":{},"authority":{},"abstentionConditions":[],"failureSemantics":[],"status":"TEMPLATE_NOT_EVIDENCE"
    })
    dump(out/"mission-003-fault-domain-register-template.json",{
        "schemaVersion":"1.0","missionId":content["missionId"],"faultDomains":[],"injectedFaults":[],
        "circuitBreakers":[],"recoveryEvidence":[],"status":"TEMPLATE_NOT_EVIDENCE"
    })
    by_name={e["name"]:e for e in mainnet["contracts"]}
    with (out/"mission-003-proof-route.csv").open("w",newline="",encoding="utf-8") as h:
        w=csv.DictWriter(h,fieldnames=["sequence","stage","contract","address","purpose","etherscan_url"]); w.writeheader()
        for item in content["proofRoute"]:
            c=by_name[item["contractName"]]
            w.writerow({"sequence":item["sequence"],"stage":item["stage"],"contract":item["contractName"],"address":c["address"],"purpose":item["purpose"],"etherscan_url":c["etherscanUrl"]})


def add_sitemap(path: Path) -> None:
    if not path.exists(): return
    raw=path.read_text(encoding="utf-8")
    url="https://montrealai.github.io/goalos-agialpha-ascension/proof-mission-003.html"
    if url in raw: return
    entry=f"<url><loc>{url}</loc></url>"
    raw=raw.replace("</urlset>",entry+"\n</urlset>")
    path.write_text(raw,encoding="utf-8")


def main() -> int:
    ap=argparse.ArgumentParser(); ap.add_argument("--site",default="site"); ap.add_argument("--content",default="content/proof-mission-003-capability-constellation.json"); ap.add_argument("--mainnet",default="data/mainnet/v4.4.0-mainnet-2026-06-21.json"); args=ap.parse_args()
    site=Path(args.site); content=load(Path(args.content)); mainnet=load(Path(args.mainnet)); validate(content,mainnet)
    if not (site/"index.html").exists(): fail("site/index.html is missing; run the canonical builder first")
    if not (site/"proof-gradient-challenge.html").exists() or not (site/"proof-mission-002.html").exists(): fail("Mission 001/002 pages must exist before Mission 003")
    (site/PAGE).write_text(page(content,mainnet),encoding="utf-8")
    (site/HUB).write_text(hub_page(content),encoding="utf-8")
    inject_homepage(site/"index.html"); write_downloads(site,content,mainnet); add_sitemap(site/"sitemap.xml")
    qa={"status":"PASS","page":PAGE,"hub":HUB,"missionId":content["missionId"],"proofRouteContracts":len(content["proofRoute"]),"contentSha256":sha256(Path(args.content)),"mainnetDataSha256":sha256(Path(args.mainnet)),"publicNetworkTransactionSent":False}
    dump(site/"qa"/"proof-mission-003-build.json",qa); print(json.dumps(qa,indent=2)); return 0

if __name__=="__main__": raise SystemExit(main())
